using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");

            // BREAKING CHANGE 1 — Discriminator property renamed
            // EF Core 9 writes "$type" instead of "Discriminator".
            // Existing 500K documents use "Discriminator", and direct SQL
            // queries reference c.Discriminator.  Preserve the old name.
            b.HasDiscriminator<string>("Discriminator")
             .HasValue<Product>("Product");

            // BREAKING CHANGE 2 — id format changed
            // EF Core 8: id = "Product|123"   EF Core 9: id = "123"
            // Existing documents use the old format.  Map a shadow property
            // to the JSON "id" field with a generator that keeps the prefix.
            b.Property<string>("__id")
             .ToJsonProperty("id")
             .HasValueGenerator<LegacyCosmosIdGenerator>();

            // BREAKING CHANGE 3 — HasIndex() now throws for Cosmos
            // EF Core 8 silently ignored it; EF Core 9 rejects it.
            // Cosmos manages its own indexing policy — remove the call.
            // (was: b.HasIndex(p => p.Sku);)
        });
    }
}

class Product
{
    public int Id { get; set; }
    public string Sku { get; set; } = null!;
}

/// <summary>
/// Produces Cosmos id values in the EF Core 8 legacy format: "Product|{key}".
/// </summary>
class LegacyCosmosIdGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;

    protected override string NextValue(EntityEntry entry)
    {
        var discriminator = entry.Property("Discriminator").CurrentValue;
        var key = entry.Property("Id").CurrentValue;
        return $"{discriminator}|{key}";
    }
}

