class CosmosQuery
{
    // BREAKING CHANGE 4 — Synchronous I/O removed
    // EF Core 9 Cosmos no longer supports sync APIs (ToList, First, Single …).
    // All queries must use their async counterparts.
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — still works because we preserved "Discriminator"
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        var products = await ctx.Products
            .Where(p => p.Sku == "ABC")
            .ToListAsync();
    }
}

